def handle_agent_result(result: dict) -> str:
    """
    Map exit status to a user-facing message and determine whether to retry.
    """
    status = result.get("status")

    if status == "complete":
        # Success: use the result
        return f"Task completed: {result.get('result')}"

    elif status == "failed":
        # Agent explicitly gave up: surface the reason to the user
        reason = result.get("reason", "Unknown reason")
        return f"Agent reported failure: {reason}. Please try rephrasing the request."

    elif status == "max_iterations":
        # Runaway loop: log the run for investigation
        # Do NOT automatically retry — the retry will also hit max_iterations
        iters = result.get("iterations", "?")
        return (
            f"Agent did not complete after {iters} iterations. "
            "This task may be too complex or the agent may be stuck. "
            "Please try a simpler request."
        )

    elif status == "stuck":
        # Same tool repeated: retrying with different phrasing may help
        return (
            "Agent was stuck in a retry loop. "
            "Retrying with a more specific request..."
        )

    elif status == "budget_exceeded":
        # Token budget hit: return partial result if available
        return (
            "Task exceeded the token budget and was cut short. "
            "Consider breaking the task into smaller parts."
        )

    elif status == "no_tool_calls":
        # Model stopped without completing: extract the final text if any
        return "Agent stopped without completing the task. Check the last response."

    return f"Unknown status: {status}"

