import anthropic
import json

client = anthropic.Anthropic()

WRAP_UP_MESSAGE = (
    "You are approaching the context limit. "
    "Stop making tool calls. "
    "Synthesize the information you have gathered so far into the best answer you can, "
    "then call task_complete. Do not call any other tools."
)

def run_agent_with_budget_warning(
    system: str,
    tools: list,
    dispatch: dict,
    user_message: str,
    max_input_tokens: int = 80_000,
    warn_at_fraction: float = 0.75,
    max_iterations: int = 15,
) -> dict:
    messages = [{"role": "user", "content": user_message}]
    total_input_tokens = 0
    warn_threshold = int(max_input_tokens * warn_at_fraction)
    wrap_up_injected = False

    for iteration in range(1, max_iterations + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        total_input_tokens += resp.usage.input_tokens
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        # Success exits
        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input,
                        "total_input_tokens": total_input_tokens, "iterations": iteration}
            if block.name == "task_failed":
                return {"status": "failed", "reason": block.input.get("reason", ""),
                        "total_input_tokens": total_input_tokens}

        # Hard budget limit
        if total_input_tokens >= max_input_tokens:
            return {"status": "budget_exceeded", "total_input_tokens": total_input_tokens,
                    "iterations": iteration}

        # Max iterations
        if iteration >= max_iterations:
            return {"status": "max_iterations", "total_input_tokens": total_input_tokens}

        if not tool_calls:
            return {"status": "no_tool_calls", "iterations": iteration}

        # Dispatch tool results
        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

        # Soft budget warning: inject wrap-up instruction once
        if not wrap_up_injected and total_input_tokens >= warn_threshold:
            messages.append({"role": "user", "content": WRAP_UP_MESSAGE})
            wrap_up_injected = True

    return {"status": "max_iterations"}

import anthropic
import json
import threading
import time

client = anthropic.Anthropic()

class TimeoutController:
    """
    Enforces a wall-clock deadline across agent iterations.
    Thread-safe: can be checked from the main loop.
    """
    def __init__(self, deadline_seconds: float):
        self._start = time.monotonic()
        self._deadline = deadline_seconds
        self._exceeded = False
        self._lock = threading.Lock()

    def check(self) -> bool:
        """Returns True if the deadline has been exceeded."""
        with self._lock:
            if not self._exceeded:
                self._exceeded = (time.monotonic() - self._start) >= self._deadline
            return self._exceeded

    def remaining(self) -> float:
        """Seconds remaining before deadline (0 if already exceeded)."""
        elapsed = time.monotonic() - self._start
        return max(0.0, self._deadline - elapsed)

def run_agent_with_timeout(
    system: str,
    tools: list,
    dispatch: dict,
    user_message: str,
    timeout_seconds: float = 60.0,
    max_iterations: int = 15,
) -> dict:
    timer = TimeoutController(timeout_seconds)
    messages = [{"role": "user", "content": user_message}]

    for iteration in range(1, max_iterations + 1):
        # Check timeout BEFORE making the API call
        if timer.check():
            return {"status": "timeout", "iterations": iteration,
                    "remaining_seconds": 0}

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "result": block.input,
                        "elapsed_seconds": timeout_seconds - timer.remaining()}

        if not tool_calls:
            return {"status": "no_tool_calls", "iterations": iteration}

        # Check again AFTER the (potentially slow) API call
        if timer.check():
            return {"status": "timeout", "iterations": iteration}

        results = []
        for block in tool_calls:
            fn = dispatch.get(block.name)
            result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "max_iterations"}
